    88→/**
    89→ * Configures CORS for the application.
    90→ * 
    91→ * Supports two modes via environment variables:
    92→ * - CORS_ORIGIN_PATTERN: Regex pattern for dynamic origin matching (e.g. "^https://([a-z0-9-]+\\.)?prixm\\.ai$")
    93→ * - ENABLE_CORS_BASE_URL: Static origin string (legacy, single origin only)
    94→ * 
    95→ * If neither is set, CORS is enabled with no origin restrictions.
    96→ */
    97→function configureCors(app: INestApplication) {
    98→  const corsConfig = {
    99→    methods: 'GET,HEAD,PUT,PATCH,POST,DELETE',
   100→    allowedHeaders: ['Content-Type', 'Accept', 'Authorization', 'Cookie'],
   101→    exposedHeaders: ['Set-Cookie'],
   102→    credentials: true,
   103→  };
   104→
   105→  if (process.env.CORS_ORIGIN_PATTERN) {
   106→    const corsPattern = new RegExp(process.env.CORS_ORIGIN_PATTERN);
   107→    console.log(`CORS: Using pattern ${process.env.CORS_ORIGIN_PATTERN}`);
   108→
   109→    app.enableCors({
   110→      origin: (origin, callback) => {
   111→        if (!origin || corsPattern.test(origin)) {
   112→          callback(null, origin || true);
   113→        } else {
   114→          callback(new Error('Not allowed by CORS'));
   115→        }
   116→      },
   117→      ...corsConfig,
   118→    });
   119→  } else if (process.env.ENABLE_CORS_BASE_URL) {
   120→    console.log(`CORS: Using static origin ${process.env.ENABLE_CORS_BASE_URL}`);
   121→    app.enableCors({
   122→      origin: process.env.ENABLE_CORS_BASE_URL,
   123→      ...corsConfig,
   124→    });
   125→  } else {
   126→    console.log('CORS: No origin restrictions set');
   127→    app.enableCors(corsConfig);
   128→  }
   129→}

